1444	// importUsers imports users as _user blueprint entities.
1445	// New users are created with STAGED status (or DISABLED for non-admins when usersAsDisabled is true).
1446	// Existing users are updated with source data as-is.
1447	func (i *Importer) importUsers(ctx context.Context, users []api.User, result *Result, _ *WorkerPool, usersAsDisabled bool) {
1448		// Index by email for conflict resolution
1449		byEmail := make(map[string]api.User, len(users))
1450		for _, u := range users {
1451			if email, ok := u["email"].(string); ok && email != "" {
1452				byEmail[email] = u
1453			}
1454		}
1455	
1456		for start := 0; start < len(users); start += userBatchSize {
1457			end := start + userBatchSize
1458			if end > len(users) {
1459				end = len(users)
1460			}
1461			batch := users[start:end]
1462	
1463			entities := make([]api.Entity, 0, len(batch))
1464			for _, u := range batch {
1465				if email, ok := u["email"].(string); !ok || email == "" {
1466					continue
1467				}
1468				status := userStatusForCreate(u, usersAsDisabled)
1469				entities = append(entities, UserToEntity(u, status))
1470			}
1471			if len(entities) == 0 {
1472				continue
1473			}
1474	
1475			errs, err := i.client.CreateUserEntitiesBulk(ctx, entities, false)
1476			if err != nil {
1477				i.mu.Lock()
1478				for _, e := range entities {
1479					if email, ok := e["identifier"].(string); ok {
1480						i.errors.Add(err, "user", email)
1481					}
1482				}
1483				i.mu.Unlock()
1484				continue
1485			}
1486	
1487			i.mu.Lock()
1488			result.UsersCreated += len(entities) - len(errs)
1489			i.mu.Unlock()
1490	
1491			// Collect conflicting users and re-POST with upsert=true, source data as-is
1492			var conflictEntities []api.Entity
1493			var nonConflictErrs []api.BulkEntityError
1494			for _, be := range errs {
1495				if int(be.StatusCode) == 409 {
1496					if orig, ok := byEmail[be.Identifier]; ok {
1497						conflictEntities = append(conflictEntities, UserToEntity(orig, ""))
1498					}
1499				} else {
1500					nonConflictErrs = append(nonConflictErrs, be)
1501				}
1502			}
1503	
1504			for _, be := range nonConflictErrs {
1505				i.mu.Lock()
1506				i.errors.Add(fmt.Errorf("%s: %s", be.Error, be.Message), "user", be.Identifier)
1507				i.mu.Unlock()
1508			}
1509	
1510			if len(conflictEntities) > 0 {
1511				updateErrs, updateErr := i.client.CreateUserEntitiesBulk(ctx, conflictEntities, true)
1512				if updateErr != nil {
1513					i.mu.Lock()
1514					for _, e := range conflictEntities {
1515						if email, ok := e["identifier"].(string); ok {
1516							i.errors.Add(updateErr, "user", email)
1517						}
1518					}
1519					i.mu.Unlock()
1520				} else {
1521					i.mu.Lock()
1522					result.UsersUpdated += len(conflictEntities) - len(updateErrs)
1523					i.mu.Unlock()
1524					for _, be := range updateErrs {
1525						i.mu.Lock()
1526						i.errors.Add(fmt.Errorf("%s: %s", be.Error, be.Message), "user", be.Identifier)
1527						i.mu.Unlock()
1528					}
1529				}
1530			}
1531		}
1532	}
