		end := start + UserBatchSize
		if end > len(users) {
			end = len(users)
		}
		batch := users[start:end]

		entities := make([]api.Entity, 0, len(batch))
		for _, u := range batch {
			if email, ok := u["email"].(string); !ok || email == "" {
